var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"Whew...","TWN":"呼……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아주머니, 저도 그냥 신분증 하나 사서 고향으로 내려갈까 봐요.","JPN":"おばさん、私も身分証を買って故郷に帰っちゃいますかね。","ENG":"Madam, I think I’ll go buy an ID card and go down to my hometown.","TWN":"伯母，我可能會買個身分證回老家去。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"으응……? 손님……. 집으로 가려고……?","JPN":"ん……？　お客さん……家に帰るつもり……？","ENG":"Huh...? Are you... going home...?","TWN":"嗯……？客人……你要回家喔……？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"레아가 좋아하는 것 같던데……. 조금만 더 있다 가지…….","JPN":"レアが気に入ってたのに……もう少しゆっくりして行ったら……","ENG":"But Leah seems to like you... Stay just a little longer...","TWN":"我們蕾亞好像很喜歡你……你再多待幾天嘛……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그건 그냥 찌그러진 레서판다 보고 귀여워하는 느낌이라고 생각하는데요.","JPN":"それはただぺちゃんこになったレッサーパンダーを見てかわいがっている感じだと思いますよ。","ENG":"Likes me? I think it’s more like she sees me as this cute red panda that’s nice to have around.","TWN":"她只是覺得小貓熊很可愛吧？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……레서판다가 어떻게 생긴 동물인지는 잘 모르지만요.","JPN":"……レッサーパンダーがどんな動物かはよくわかりませんが。","ENG":"...Though to be honest I’m not even really sure what a red panda looks like.","TWN":"……雖然我也不知道小貓熊長什麼樣。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"후후……. 생긴 것도 하는 것도 아주 깜찍한 동물이지…….","JPN":"ふふ……見かけも、やることもとってもかわいらしい動物ね……","ENG":"Ha ha... It’s an animal that looks cute and acts cute...","TWN":"呵呵……小貓熊的長相和動作都很可愛喔……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"허어……. 그렇다면 다행이네요.","JPN":"へえ……それはよかったですね。","ENG":"Huh. That’s good then, I guess.","TWN":"喔……那還好。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"사실 어릴 때 입 삐죽거린다고 오리 너구리란 소리도 들었거든요.","JPN":"実は小さい頃、口を尖らせるからカモノハシって言われたこともあったんです。","ENG":"When I was little, I heard I looked like the ugly duckling whenever I pouted.","TWN":"我小時候常扁嘴，還有人說我是鴨嘴獸呢。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"브레히트 중사님.","JPN":"ブレヒト軍曹。","ENG":"Sergeant Brecht.","TWN":"布萊希特中士，"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"현재 본 기로 접근 중인 인물이 포착되었습니다. 무장한 상태예요.","JPN":"現在、本機に接近している人物が確認されました。武装状態です。","ENG":"I’ve detected someone approaching this ship. They are armed.","TWN":"發現有武裝份子正在接近本機。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그러면 허탕 치라고 부리나케 도망쳐야죠.","JPN":"だったら、肩透かしを食らわすためにも急いで逃げないとね。","ENG":"Well, then clearly we should make like a tree and get out of here now.","TWN":"那應該三十六計走為上策吧！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아주머니, 잠깐 실례할게요.","JPN":"おばさん、ちょっと失礼します。","ENG":"Excuse me for a moment, Madam.","TWN":"伯母，失禮囉！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아윽?!","JPN":"あうっ！？","ENG":"Ugh!","TWN":"呃？！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_HIT_BLADE_BIG_04"},{"id":"L23_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"소, 손님……!","JPN":"お、お客さん……！","ENG":"A-are you..!","TWN":"客…客人……！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"함교에 침입자 감지!","JPN":"艦橋に侵入者を感知！","ENG":"Detecting an intruder on the bridge!","TWN":"有人入侵艦橋！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L26_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"어떻게 된 거죠? 감시망에는 분명 신호가……!","JPN":"どういうことですか？　確か監視網では信号が……！","ENG":"What happened? I should have been able to pick up a signal on the surveillance network.","TWN":"怎麼會這樣？監視網怎麼沒……！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"관리국의 기술이 아무리 뛰어나도, 테라브레인이 아닌 보급형이라면 허점은 찾을 수 있어.","JPN":"管理局の技術がいくら優れていても、テラブレインではない普及型なら隙は見つけられる。","ENG":"No matter how good the technology of the Administration, you can always find a loophole if it is a low end type and not a Terrabrain.","TWN":"就算管理局的技術再怎麼厲害，不是特拉大腦的話，一般補給型還是找得到弱點的。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"원리만 알면 재머 만드는 것쯤이야 식은 죽 먹기지.","JPN":"原理さえわかれば、ジャマーを作るのは朝飯前。","ENG":"If you know the fundamentals, it’s easy to make a jammer.","TWN":"只要知道原理，再弄個干擾器，根本是易如反掌。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"모네카, 널 두고 하는 말이야.","JPN":"モネカ、あなたのことだ。","ENG":"I’m talking about you, Moneka.","TWN":"莫奈卡，我這話是針對你說的。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"唔……！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"손님……. 피, 피가 나……. 이를 어째…….","JPN":"お客さん……ち、血が出て……どうすれば……","ENG":"Y-You’re bleeding... What should I...","TWN":"客人……你流血了……怎麼辦……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"괜찮아요. 이런 부상은……. 후방 이송도 안 되는 수준이니까.","JPN":"大丈夫です、この程度は……後方移送されるにも及びませんよ。","ENG":"I’m fine. These injuries... wouldn’t even get me transferred to the rear.","TWN":"沒事的，這點小傷……跟被蚊子咬差不多。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"당신이 몽타뉴죠? 레버넌트 씨와 원수라던?","JPN":"あなたがモンターニュですね？　レヴナントさんの敵の？","ENG":"I guess you must be Montagne? Revenant’s enemy?","TWN":"你就是和亡靈小姐互相仇視的蒙塔妮吧？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"일방적인 원한이었지. 지금까지는.","JPN":"一方的な恨みだった。今までは。","ENG":"Well, the grudge has been fairly one-sided. Until now.","TWN":"目前是我單方面仇視她，"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"하지만 너랑 저 노파 시체를 건국기념전당 위에 걸어 두면…….","JPN":"でもあなたと、あの老婆の死体を建国記念館の上に飾っておけば……","ENG":"But if we hang you and that old woman on top of the National Foundation Hall...","TWN":"等我把你和老太婆的屍體掛在建國紀念堂上之後……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"그때부터는 쌍방이 될 거야.","JPN":"それからは双方の恨みになるはずだ。","ENG":"After that, the grudge will be mutual.","TWN":"到時就會變成彼此仇視。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그동안 지켜봤으면 알 거 아니에요. 레버넌트 씨는 그 그림자랑 전혀 다른 사람이에요.","JPN":"今まで見ていたならわかるでしょ？　レヴナントさんはあのシャドウとはまったくの別人です。","ENG":"You should already know the truth if you’ve been watching us. Revenant is a completely different person from that Shadow.","TWN":"這段時間看下來你應該也很清楚吧？亡靈小姐完全不像是暗影。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"생면부지인 사람 죄를 갚으라고 윽박지르는 셈인데 미친 거 아니에요?!","JPN":"知らない人の罪を償えと言っているわけですよ。正気ですか！？","ENG":"You’re judging a complete stranger for someone else’s sins, you’re crazy!!","TWN":"竟然向一個素未謀面的人尋仇，你腦袋是不是有問題？！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"모른다고 잡아떼면 과거가 지워지다니, 참 편한 세상에서 성장했나 보군.","JPN":"知らないと言ったら過去が無くなるなんて、楽な世界で育ったものだ。","ENG":"So if one denies any wrongdoing the past should be erased? Truly you must have grown up in a comfortable world.","TWN":"一句不像就想推翻過去發生的事，你是不是有點天真？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"그리고 시간 끌어 봤자 소용없어. 모네카는 지금 오프라인 상태거든.","JPN":"それに、時間を稼いでも無駄だ。モネカは今オフライン状態だから。","ENG":"Oh, and it’s no use stalling. Moneka is offline right now.","TWN":"另外，你這樣拖時間也沒用，莫奈卡現在是離線狀態。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……저기, 진짜예요?","JPN":"……あの、本当ですか？","ENG":"...I-Is that true?","TWN":"……她說的是真的嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"네에……. 죄송해요. 모처럼 믿어 주셨는데.","JPN":"はい……ごめんなさい。せっかく信頼してもらいましたのに。","ENG":"Yes... I’m sorry. I’ve failed you...","TWN":"是真的……抱歉，好不容易才取得你的信任。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"허어…….","JPN":"ほほう……","ENG":"What...","TWN":"哀……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"우리 오빠는, 오빠를 따르던 부하들 앞에서 짐승보다 못한 꼴을 보여 주고 죽었어.","JPN":"私の兄さんは自分に従っていた部下たちの前で、獣以下の醜態を晒しながら死んだ。","ENG":"My brother died in front of his own men, he was displayed to them as something worse than a beast.","TWN":"我哥，在他的隊員面前死相有多淒慘，"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"당연히 너희도 그만큼 비참하게 죽어야 형평성에 맞지.","JPN":"当然、あなたたちにもそれ相応の死に方をしてもらわないと釣り合わない。","ENG":"It is only fair that you die in similar fashion.","TWN":"你們當然也要死得跟我哥一樣淒慘，這樣才公平吧？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"지, 진짜 미쳤어……!","JPN":"ほ、本当に狂っている……！","ENG":"Y-You’re crazy...!","TWN":"你…你真的瘋了……！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"그래도 미리 겁내지는 마. 나는 예전에도 창의력이 뛰어난 편은 아니었거든.","JPN":"そんな今から怯えることない。私は昔からクリエイティブな方ではなかったから。","ENG":"Oh, don’t worry so much in advance. I was never able to be that creative, even in the past.","TWN":"不過你們還不需要感到害怕，我以前也沒這麼有創意。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"진짜……!","JPN":"本当に……！","ENG":"You...!","TWN":"你真的……！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"미쳤나 봐. 자기 뒤통수는 생각도 안 하고.","JPN":"狂っているみたいね。自分の後ろを全然気にしないなんて。","ENG":"You must be crazy. To not be worried at all about what’s behind you.","TWN":"有病！病到連後腦勺失守都不知道！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"……뭐?","JPN":"……なん……だと？","ENG":"...What did you say?","TWN":"……什麼？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"동작 그만.","JPN":"そこまでよ。","ENG":"Don’t move.","TWN":"別動。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"다시 만나서 반가워, 저격수. 몽타뉴라고 했던가.","JPN":"また会えてうれしいね、スナイパー。モンターニュって名前だっけ。","ENG":"Nice to see you again, sniper. You said your name was... Montagne?","TWN":"又見面啦，狙擊手，你是叫蒙塔妮？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"손 들고 이쪽으로 돌아서.","JPN":"手を上げてこっちを向いて。","ENG":"Put your hands up and turn this way.","TWN":"手舉高轉過身來。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"……완전히 읽혔군.","JPN":"……完全に読まれたか。","ENG":"...You predicted this completely.","TWN":"……被你識破了嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"다행히도 말이야.","JPN":"……幸いにね。","ENG":"Fortunately, yes.","TWN":"老天保佑。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"오빠를 떠내보낸 건 안타깝지만, 우리는 네가 복수해야 할 상대가 아냐.","JPN":"お兄さんが死んだのは気の毒だけど、私たちは君の仇討の相手じゃないよ。","ENG":"It truly is regrettable about what happened to your brother, but we’re not the right targets for your revenge.","TWN":"你哥的事我也很遺憾，但你該報仇的對象不是我們。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"무기 내려 놓고 손 들어. 묵비권을 행사할 권리는 있을 거야.","JPN":"武器を下ろして手を上げて。黙秘権を行使する権利はあるはずだろうね。","ENG":"Drop your weapon and put your hands up. You have the right to remain silent, probably.","TWN":"放下武器，手舉高，你有權利保持沈默。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"반역자란 녀석이…… 아직도 공작원 행세인가? 웃기는군.","JPN":"反逆者ってやつが……まだ工作員のつもり？　笑える。","ENG":"Treacherous bastard... Are you still pretending to be an operative? That’s hilarious.","TWN":"明明是叛國罪犯……你以為自己還是情報員嗎？在那邊裝腔作勢的，真可笑！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그러게. 준법 정신이 생각보다 투철한가 봐.","JPN":"そうね。思ったより順法精神が徹底しているみたい。","ENG":"I know. I guess I am more compliant than I thought I’d be.","TWN":"是欸，職業病比我想像中還嚴重呢。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"내 눈앞에 있는 저 둘만 해치우면 가장 중요한 목표는 달성돼.","JPN":"目の前にいるあの二人だけやれば、一番大事な目標は達成する。","ENG":"If I get rid of the two standing in front of me, my most important objective will be complete.","TWN":"我只要解決掉眼前二人，就算是達成最重要的目標。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"나는 어차피 시한부 환자야. 이면세계를 표류하는 동안 광물질이 내 몸 속에서 자라나더군.","JPN":"私はしょせん死亡宣告を受けた身。裏世界を漂流するうちに、鉱物質が私の体内で増殖したらしい。","ENG":"I don’t have long for this world anyways. Minerals grew in my body while I was drifting along Counterside.","TWN":"反正我再活也沒多久，在異界漂流的時候，我體內還長出礦物質呢。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"무기 내려. 마지막 경고야.","JPN":"武器を下ろして。最後の警告よ。","ENG":"Drop your weapon. This is your last warning.","TWN":"我最後一次警告你，放下武器。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그렇게 복수하고 싶다면 차라리 다음 기회를 노려. 살아남는다면 다음이 있잖아.","JPN":"そんなに復讐したいなら、いっそ次のチャンスを狙って。生き延びたら次があるでしょう？","ENG":"If you want revenge so bad, you’d be better off waiting for a better chance. If you survive now, there could still be a next time.","TWN":"你那麼想報仇的話，何不等下一次的機會？只要活著就還有機會。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"왜? 가족 앞에서 손에 피 묻히기 무섭나?","JPN":"なぜ？　家族の前で手を汚すことが怖いのか？","ENG":"Why the hesitation? Are you scared to get your hands bloody in front of your family?","TWN":"怎麼？不想在家人面前大開殺戒嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"오빠가 죽은 뒤로 목숨에 미련 따위 없었어.","JPN":"兄さんが死んで以来、命に未練なんてなかった。","ENG":"I had nothing on the table ever since my brother died.","TWN":"自從我哥死後，我便將生死置之度外。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"하다못해 내 죽음이 저들의 뇌리에 상처로 남을 수 있다면…….","JPN":"せめて私の死をあの者たちの脳裏に傷として残せるなら……","ENG":"If at the very least, my dying traumatizes them in some way...","TWN":"若是我的性命，可以換來在她們腦袋上開洞……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"몽타뉴!","JPN":"モンターニュ！","ENG":"Montagne!","TWN":"蒙塔妮！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"……기꺼이 버린다.","JPN":"……喜んで捨てる。","ENG":"...I would be willing to die now.","TWN":"……那我非常樂意。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"둘 다 눈 감아!!","JPN":"二人とも目閉じて！！","ENG":"Both of you, close your eyes!!","TWN":"你們兩個閉眼睛！！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};